+      providerCallId: callSid,
+      timestamp,
+      direction: (callerMeta.direction ?? "inbound") as "inbound" | "outbound",
+      ...(callerMeta.from ? { from: callerMeta.from } : {}),
+      ...(callerMeta.to ? { to: callerMeta.to } : {}),
+    };
